{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::l2_distance_batch;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

const DIM: usize = 128;
const NUM_CLUSTERS: usize = 8192;
const NPROBE: usize = 80;
const SAMPLE_SIZE: usize = 120000;
const KMEANS_ITERS: usize = 12;

pub struct VectorDB {
    pending_vectors: RwLock<Vec<f32>>,
    pending_ids: RwLock<Vec<u64>>,
    pending_count: AtomicUsize,

    index: RwLock<Option<Box<IVFIndex>>>,
    indexed: AtomicBool,
}

struct IVFIndex {
    centroids: Vec<f32>,
    cluster_vectors: Vec<f32>,
    cluster_ids: Vec<u64>,
    cluster_offsets: Vec<usize>,
    n_clusters: usize,
}

impl VectorDB {
    pub fn new() -> Self {
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        Self {
            pending_vectors: RwLock::new(Vec::with_capacity(1_100_000 * DIM)),
            pending_ids: RwLock::new(Vec::with_capacity(1_100_000)),
            pending_count: AtomicUsize::new(0),
            index: RwLock::new(None),
            indexed: AtomicBool::new(false),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vecs = self.pending_vectors.write();
        let mut ids = self.pending_ids.write();
        vecs.extend_from_slice(&vector);
        ids.push(id);
        self.pending_count.fetch_add(1, Ordering::Relaxed);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut vecs = self.pending_vectors.write();
        let mut ids = self.pending_ids.write();
        for (id, vector) in &vectors {
            vecs.extend_from_slice(vector);
            ids.push(*id);
        }
        self.pending_count.fetch_add(count, Ordering::Relaxed);
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        if !self.indexed.load(Ordering::Acquire) {
            self.build_index();
        }

        let top_k = top_k as usize;
        let index_guard = self.index.read();
        let idx = index_guard.as_ref().unwrap();

        let nprobe = NPROBE.min(idx.n_clusters);

        // Compute distance to all centroids
        let mut centroid_dists = vec![0.0f32; idx.n_clusters];
        l2_distance_batch(vector, &idx.centroids, idx.n_clusters, &mut centroid_dists);

        // Find top NPROBE nearest clusters
        let mut cluster_indices: Vec<u16> = (0..idx.n_clusters as u16).collect();
        let cd = &centroid_dists;
        cluster_indices.select_nth_unstable_by(nprobe - 1, |&a, &b| {
            cd[a as usize].partial_cmp(&cd[b as usize]).unwrap()
        });

        // Sort top nprobe for better pruning (closest first)
        cluster_indices[..nprobe].sort_unstable_by(|&a, &b| {
            cd[a as usize].partial_cmp(&cd[b as usize]).unwrap()
        });

        // Fixed-size max-heap for top-k
        let mut heap_dists = [f32::MAX; 16];
        let mut heap_ids = [0u64; 16];
        let mut heap_size = 0usize;
        let actual_k = top_k.min(16);
        let mut threshold = f32::MAX;
        let mut distances_buf = vec![0.0f32; 1024];

        for idx_i in 0..nprobe {
            let ci = cluster_indices[idx_i] as usize;
            let start = idx.cluster_offsets[ci];
            let end = idx.cluster_offsets[ci + 1];
            let n = end - start;
            if n == 0 {
                continue;
            }

            if distances_buf.len() < n {
                distances_buf.resize(n, 0.0);
            }

            let vecs_slice = &idx.cluster_vectors[start * DIM..end * DIM];
            let ids_slice = &idx.cluster_ids[start..end];

            l2_distance_batch(vector, vecs_slice, n, &mut distances_buf);

            for j in 0..n {
                let dist = distances_buf[j];

                if dist >= threshold && heap_size >= actual_k {
                    continue;
                }

                if heap_size < actual_k {
                    heap_dists[heap_size] = dist;
                    heap_ids[heap_size] = ids_slice[j];
                    heap_size += 1;
                    let mut i = heap_size - 1;
                    while i > 0 {
                        let parent = (i - 1) / 2;
                        if heap_dists[i] > heap_dists[parent] {
                            heap_dists.swap(i, parent);
                            heap_ids.swap(i, parent);
                            i = parent;
                        } else {
                            break;
                        }
                    }
                    if heap_size == actual_k {
                        threshold = heap_dists[0];
                    }
                } else {
                    heap_dists[0] = dist;
                    heap_ids[0] = ids_slice[j];
                    let mut i = 0;
                    loop {
                        let left = 2 * i + 1;
                        let right = 2 * i + 2;
                        let mut largest = i;
                        if left < actual_k && heap_dists[left] > heap_dists[largest] {
                            largest = left;
                        }
                        if right < actual_k && heap_dists[right] > heap_dists[largest] {
                            largest = right;
                        }
                        if largest != i {
                            heap_dists.swap(i, largest);
                            heap_ids.swap(i, largest);
                            i = largest;
                        } else {
                            break;
                        }
                    }
                    threshold = heap_dists[0];
                }
            }
        }

        let mut results: Vec<(f32, u64)> = (0..heap_size)
            .map(|i| (heap_dists[i], heap_ids[i]))
            .collect();
        results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());

        results
            .iter()
            .map(|&(dist, id)| SearchResult {
                id,
                distance: dist as f64,
            })
            .collect()
    }

    fn build_index(&self) {
        if self.indexed.swap(true, Ordering::AcqRel) {
            return;
        }

        let vecs = self.pending_vectors.read();
        let ids = self.pending_ids.read();
        let n = ids.len();

        if n == 0 {
            return;
        }

        let n_clusters = NUM_CLUSTERS.min(n);
        eprintln!("Building index: {} vectors, {} clusters", n, n_clusters);

        let centroids = self.run_kmeans(&vecs, n, n_clusters);

        let chunk_size = 5000;
        let n_chunks = (n + chunk_size - 1) / chunk_size;

        let all_assignments: Vec<usize> = {
            let chunks: Vec<Vec<usize>> = (0..n_chunks)
                .into_par_iter()
                .map(|chunk_idx| {
                    let start = chunk_idx * chunk_size;
                    let end = (start + chunk_size).min(n);
                    let mut centroid_dists = vec![0.0f32; n_clusters];
                    let mut local = Vec::with_capacity(end - start);

                    for i in start..end {
                        let vec_slice = &vecs[i * DIM..(i + 1) * DIM];
                        l2_distance_batch(vec_slice, &centroids, n_clusters, &mut centroid_dists);

                        let mut best_idx = 0;
                        let mut best_dist = f32::MAX;
                        for (ci, &d) in centroid_dists.iter().enumerate() {
                            if d < best_dist {
                                best_dist = d;
                                best_idx = ci;
                            }
                        }
                        local.push(best_idx);
                    }
                    local
                })
                .collect();

            let mut result = Vec::with_capacity(n);
            for chunk in chunks {
                result.extend(chunk);
            }
            result
        };

        let mut cluster_sizes = vec![0usize; n_clusters];
        for &ci in &all_assignments {
            cluster_sizes[ci] += 1;
        }

        let mut offsets = vec![0usize; n_clusters + 1];
        for i in 0..n_clusters {
            offsets[i + 1] = offsets[i] + cluster_sizes[i];
        }

        let mut cluster_vecs = vec![0.0f32; n * DIM];
        let mut cluster_ids_arr = vec![0u64; n];
        let mut write_pos = offsets[..n_clusters].to_vec();

        for i in 0..n {
            let ci = all_assignments[i];
            let pos = write_pos[ci];
            write_pos[ci] += 1;
            cluster_ids_arr[pos] = ids[i];
            let dst_start = pos * DIM;
            cluster_vecs[dst_start..dst_start + DIM]
                .copy_from_slice(&vecs[i * DIM..(i + 1) * DIM]);
        }

        *self.index.write() = Some(Box::new(IVFIndex {
            centroids,
            cluster_vectors: cluster_vecs,
            cluster_ids: cluster_ids_arr,
            cluster_offsets: offsets,
            n_clusters,
        }));

        drop(vecs);
        drop(ids);
        *self.pending_vectors.write() = Vec::new();
        *self.pending_ids.write() = Vec::new();

        eprintln!("Index built successfully");
    }

    fn run_kmeans(&self, vecs: &[f32], n: usize, k: usize) -> Vec<f32> {
        let sample_n = SAMPLE_SIZE.min(n);
        let step = n as f64 / sample_n as f64;
        let sample_indices: Vec<usize> = (0..sample_n)
            .map(|i| ((i as f64 * step) as usize).min(n - 1))
            .collect();

        let mut centroids = vec![0.0f32; k * DIM];
        let init_step = sample_n as f64 / k as f64;
        for i in 0..k {
            let src_idx = sample_indices[((i as f64 * init_step) as usize).min(sample_n - 1)];
            centroids[i * DIM..(i + 1) * DIM]
                .copy_from_slice(&vecs[src_idx * DIM..(src_idx + 1) * DIM]);
        }

        for _iter in 0..KMEANS_ITERS {
            let assignments: Vec<usize> = sample_indices
                .par_chunks(2500)
                .flat_map(|chunk| {
                    let mut centroid_dists = vec![0.0f32; k];
                    chunk
                        .iter()
                        .map(|&sample_idx| {
                            let vec_slice = &vecs[sample_idx * DIM..(sample_idx + 1) * DIM];
                            l2_distance_batch(vec_slice, &centroids, k, &mut centroid_dists);

                            let mut best_idx = 0;
                            let mut best_dist = f32::MAX;
                            for (ci, &d) in centroid_dists.iter().enumerate() {
                                if d < best_dist {
                                    best_dist = d;
                                    best_idx = ci;
                                }
                            }
                            best_idx
                        })
                        .collect::<Vec<_>>()
                })
                .collect();

            let mut new_centroids = vec![0.0f64; k * DIM];
            let mut counts = vec![0usize; k];

            for (si, &sample_idx) in sample_indices.iter().enumerate() {
                let ci = assignments[si];
                counts[ci] += 1;
                let src = &vecs[sample_idx * DIM..(sample_idx + 1) * DIM];
                let dst = &mut new_centroids[ci * DIM..(ci + 1) * DIM];
                for d in 0..DIM {
                    dst[d] += src[d] as f64;
                }
            }

            for ci in 0..k {
                if counts[ci] > 0 {
                    let c = counts[ci] as f64;
                    for d in 0..DIM {
                        centroids[ci * DIM + d] = (new_centroids[ci * DIM + d] / c) as f32;
                    }
                }
            }
        }

        centroids
    }
}
"}

{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::l2_distance_batch;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

const DIM: usize = 128;

// Two-level IVF: coarse clusters -> fine clusters -> vectors
const NUM_COARSE: usize = 128;    // Level 1 clusters
const NUM_FINE: usize = 4096;     // Level 2 clusters total
const NPROBE_COARSE: usize = 8;   // Search top 8 coarse clusters
const NPROBE_FINE: usize = 64;    // Search top 64 fine clusters total

const SAMPLE_SIZE: usize = 120000;
const KMEANS_ITERS: usize = 12;

pub struct VectorDB {
    pending_vectors: RwLock<Vec<f32>>,
    pending_ids: RwLock<Vec<u64>>,
    pending_count: AtomicUsize,

    index: RwLock<Option<Box<IVFIndex>>>,
    indexed: AtomicBool,
}

struct IVFIndex {
    centroids: Vec<f32>,        // [NUM_FINE * DIM] - fine centroids
    cluster_vectors: Vec<f32>,  // All vectors, grouped by fine cluster
    cluster_ids: Vec<u64>,
    cluster_offsets: Vec<usize>, // [NUM_FINE + 1]
    n_clusters: usize,

    // Coarse level
    coarse_centroids: Vec<f32>,    // [NUM_COARSE * DIM]
    coarse_to_fine: Vec<Vec<u16>>, // For each coarse cluster, list of fine cluster indices
    n_coarse: usize,
}

impl VectorDB {
    pub fn new() -> Self {
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        Self {
            pending_vectors: RwLock::new(Vec::with_capacity(1_100_000 * DIM)),
            pending_ids: RwLock::new(Vec::with_capacity(1_100_000)),
            pending_count: AtomicUsize::new(0),
            index: RwLock::new(None),
            indexed: AtomicBool::new(false),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vecs = self.pending_vectors.write();
        let mut ids = self.pending_ids.write();
        vecs.extend_from_slice(&vector);
        ids.push(id);
        self.pending_count.fetch_add(1, Ordering::Relaxed);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut vecs = self.pending_vectors.write();
        let mut ids = self.pending_ids.write();
        for (id, vector) in &vectors {
            vecs.extend_from_slice(vector);
            ids.push(*id);
        }
        self.pending_count.fetch_add(count, Ordering::Relaxed);
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        if !self.indexed.load(Ordering::Acquire) {
            self.build_index();
        }

        let top_k = top_k as usize;
        let index_guard = self.index.read();
        let idx = index_guard.as_ref().unwrap();

        // Step 1: Find nearest coarse clusters
        let mut coarse_dists = vec![0.0f32; idx.n_coarse];
        l2_distance_batch(vector, &idx.coarse_centroids, idx.n_coarse, &mut coarse_dists);

        let nprobe_coarse = NPROBE_COARSE.min(idx.n_coarse);
        let mut coarse_indices: Vec<u8> = (0..idx.n_coarse as u8).collect();
        let cd = &coarse_dists;
        coarse_indices.select_nth_unstable_by(nprobe_coarse - 1, |&a, &b| {
            cd[a as usize].partial_cmp(&cd[b as usize]).unwrap()
        });

        // Step 2: Gather candidate fine clusters from nearest coarse clusters
        let mut candidate_fine: Vec<u16> = Vec::with_capacity(NPROBE_FINE * 2);
        for &ci in &coarse_indices[..nprobe_coarse] {
            candidate_fine.extend_from_slice(&idx.coarse_to_fine[ci as usize]);
        }
        candidate_fine.sort_unstable();
        candidate_fine.dedup();

        // Step 3: Compute distances to candidate fine centroids only
        let nprobe_fine = NPROBE_FINE.min(candidate_fine.len());

        if candidate_fine.len() <= nprobe_fine {
            // Search all candidates
        } else {
            // Compute distances to candidate centroids and pick top nprobe_fine
            let mut fine_dists: Vec<(f32, u16)> = candidate_fine.iter().map(|&fi| {
                let cstart = fi as usize * DIM;
                let mut dist_buf = [0.0f32; 1];
                l2_distance_batch(vector, &idx.centroids[cstart..cstart + DIM], 1, &mut dist_buf);
                (dist_buf[0], fi)
            }).collect();

            fine_dists.select_nth_unstable_by(nprobe_fine - 1, |a, b| {
                a.0.partial_cmp(&b.0).unwrap()
            });
            fine_dists.truncate(nprobe_fine);
            // Sort by distance for better pruning
            fine_dists.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
            candidate_fine = fine_dists.iter().map(|&(_, fi)| fi).collect();
        }

        // Step 4: Search within selected fine clusters
        let mut heap_dists = [f32::MAX; 16];
        let mut heap_ids = [0u64; 16];
        let mut heap_size = 0usize;
        let actual_k = top_k.min(16);
        let mut threshold = f32::MAX;
        let mut distances_buf = vec![0.0f32; 1024];

        for &fi in &candidate_fine {
            let fi = fi as usize;
            let start = idx.cluster_offsets[fi];
            let end = idx.cluster_offsets[fi + 1];
            let n = end - start;
            if n == 0 {
                continue;
            }

            if distances_buf.len() < n {
                distances_buf.resize(n, 0.0);
            }

            let vecs_slice = &idx.cluster_vectors[start * DIM..end * DIM];
            let ids_slice = &idx.cluster_ids[start..end];

            l2_distance_batch(vector, vecs_slice, n, &mut distances_buf);

            for j in 0..n {
                let dist = distances_buf[j];

                if dist >= threshold && heap_size >= actual_k {
                    continue;
                }

                if heap_size < actual_k {
                    heap_dists[heap_size] = dist;
                    heap_ids[heap_size] = ids_slice[j];
                    heap_size += 1;
                    let mut i = heap_size - 1;
                    while i > 0 {
                        let parent = (i - 1) / 2;
                        if heap_dists[i] > heap_dists[parent] {
                            heap_dists.swap(i, parent);
                            heap_ids.swap(i, parent);
                            i = parent;
                        } else {
                            break;
                        }
                    }
                    if heap_size == actual_k {
                        threshold = heap_dists[0];
                    }
                } else {
                    heap_dists[0] = dist;
                    heap_ids[0] = ids_slice[j];
                    let mut i = 0;
                    loop {
                        let left = 2 * i + 1;
                        let right = 2 * i + 2;
                        let mut largest = i;
                        if left < actual_k && heap_dists[left] > heap_dists[largest] {
                            largest = left;
                        }
                        if right < actual_k && heap_dists[right] > heap_dists[largest] {
                            largest = right;
                        }
                        if largest != i {
                            heap_dists.swap(i, largest);
                            heap_ids.swap(i, largest);
                            i = largest;
                        } else {
                            break;
                        }
                    }
                    threshold = heap_dists[0];
                }
            }
        }

        let mut results: Vec<(f32, u64)> = (0..heap_size)
            .map(|i| (heap_dists[i], heap_ids[i]))
            .collect();
        results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());

        results
            .iter()
            .map(|&(dist, id)| SearchResult {
                id,
                distance: dist as f64,
            })
            .collect()
    }

    fn build_index(&self) {
        if self.indexed.swap(true, Ordering::AcqRel) {
            return;
        }

        let vecs = self.pending_vectors.read();
        let ids = self.pending_ids.read();
        let n = ids.len();

        if n == 0 {
            return;
        }

        let n_fine = NUM_FINE.min(n);
        let n_coarse = NUM_COARSE.min(n_fine);
        eprintln!("Building index: {} vectors, {} fine clusters, {} coarse clusters", n, n_fine, n_coarse);

        // Build fine clusters
        let fine_centroids = self.run_kmeans(&vecs, n, n_fine);

        // Assign all vectors to fine clusters
        let chunk_size = 5000;
        let n_chunks = (n + chunk_size - 1) / chunk_size;

        let all_assignments: Vec<usize> = {
            let chunks: Vec<Vec<usize>> = (0..n_chunks)
                .into_par_iter()
                .map(|chunk_idx| {
                    let start = chunk_idx * chunk_size;
                    let end = (start + chunk_size).min(n);
                    let mut centroid_dists = vec![0.0f32; n_fine];
                    let mut local = Vec::with_capacity(end - start);

                    for i in start..end {
                        let vec_slice = &vecs[i * DIM..(i + 1) * DIM];
                        l2_distance_batch(vec_slice, &fine_centroids, n_fine, &mut centroid_dists);

                        let mut best_idx = 0;
                        let mut best_dist = f32::MAX;
                        for (ci, &d) in centroid_dists.iter().enumerate() {
                            if d < best_dist {
                                best_dist = d;
                                best_idx = ci;
                            }
                        }
                        local.push(best_idx);
                    }
                    local
                })
                .collect();

            let mut result = Vec::with_capacity(n);
            for chunk in chunks {
                result.extend(chunk);
            }
            result
        };

        // Build cluster data
        let mut cluster_sizes = vec![0usize; n_fine];
        for &ci in &all_assignments {
            cluster_sizes[ci] += 1;
        }

        let mut offsets = vec![0usize; n_fine + 1];
        for i in 0..n_fine {
            offsets[i + 1] = offsets[i] + cluster_sizes[i];
        }

        let mut cluster_vecs = vec![0.0f32; n * DIM];
        let mut cluster_ids_arr = vec![0u64; n];
        let mut write_pos = offsets[..n_fine].to_vec();

        for i in 0..n {
            let ci = all_assignments[i];
            let pos = write_pos[ci];
            write_pos[ci] += 1;
            cluster_ids_arr[pos] = ids[i];
            let dst_start = pos * DIM;
            cluster_vecs[dst_start..dst_start + DIM]
                .copy_from_slice(&vecs[i * DIM..(i + 1) * DIM]);
        }

        // Build coarse clusters from fine centroids
        let coarse_centroids = self.run_kmeans(&fine_centroids, n_fine, n_coarse);

        // Assign fine centroids to coarse clusters
        let mut coarse_to_fine: Vec<Vec<u16>> = vec![Vec::new(); n_coarse];
        let mut coarse_dists = vec![0.0f32; n_coarse];
        for fi in 0..n_fine {
            let fc = &fine_centroids[fi * DIM..(fi + 1) * DIM];
            l2_distance_batch(fc, &coarse_centroids, n_coarse, &mut coarse_dists);
            let mut best_ci = 0;
            let mut best_dist = f32::MAX;
            for (ci, &d) in coarse_dists.iter().enumerate() {
                if d < best_dist {
                    best_dist = d;
                    best_ci = ci;
                }
            }
            coarse_to_fine[best_ci].push(fi as u16);
        }

        *self.index.write() = Some(Box::new(IVFIndex {
            centroids: fine_centroids,
            cluster_vectors: cluster_vecs,
            cluster_ids: cluster_ids_arr,
            cluster_offsets: offsets,
            n_clusters: n_fine,
            coarse_centroids,
            coarse_to_fine,
            n_coarse,
        }));

        drop(vecs);
        drop(ids);
        *self.pending_vectors.write() = Vec::new();
        *self.pending_ids.write() = Vec::new();

        eprintln!("Index built successfully");
    }

    fn run_kmeans(&self, vecs: &[f32], n: usize, k: usize) -> Vec<f32> {
        let sample_n = SAMPLE_SIZE.min(n);
        let step = n as f64 / sample_n as f64;
        let sample_indices: Vec<usize> = (0..sample_n)
            .map(|i| ((i as f64 * step) as usize).min(n - 1))
            .collect();

        let mut centroids = vec![0.0f32; k * DIM];
        let init_step = sample_n as f64 / k as f64;
        for i in 0..k {
            let src_idx = sample_indices[((i as f64 * init_step) as usize).min(sample_n - 1)];
            centroids[i * DIM..(i + 1) * DIM]
                .copy_from_slice(&vecs[src_idx * DIM..(src_idx + 1) * DIM]);
        }

        for _iter in 0..KMEANS_ITERS {
            let assignments: Vec<usize> = sample_indices
                .par_chunks(2500)
                .flat_map(|chunk| {
                    let mut centroid_dists = vec![0.0f32; k];
                    chunk
                        .iter()
                        .map(|&sample_idx| {
                            let vec_slice = &vecs[sample_idx * DIM..(sample_idx + 1) * DIM];
                            l2_distance_batch(vec_slice, &centroids, k, &mut centroid_dists);

                            let mut best_idx = 0;
                            let mut best_dist = f32::MAX;
                            for (ci, &d) in centroid_dists.iter().enumerate() {
                                if d < best_dist {
                                    best_dist = d;
                                    best_idx = ci;
                                }
                            }
                            best_idx
                        })
                        .collect::<Vec<_>>()
                })
                .collect();

            let mut new_centroids = vec![0.0f64; k * DIM];
            let mut counts = vec![0usize; k];

            for (si, &sample_idx) in sample_indices.iter().enumerate() {
                let ci = assignments[si];
                counts[ci] += 1;
                let src = &vecs[sample_idx * DIM..(sample_idx + 1) * DIM];
                let dst = &mut new_centroids[ci * DIM..(ci + 1) * DIM];
                for d in 0..DIM {
                    dst[d] += src[d] as f64;
                }
            }

            for ci in 0..k {
                if counts[ci] > 0 {
                    let c = counts[ci] as f64;
                    for d in 0..DIM {
                        centroids[ci * DIM + d] = (new_centroids[ci * DIM + d] / c) as f32;
                    }
                }
            }
        }

        centroids
    }
}
