/// Compute L2 squared distance between two 128-dim f32 vectors, returned as f64.
/// Uses AVX-512 intrinsics for maximum throughput on Cascade Lake.
#[inline(always)]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), 128);
    debug_assert_eq!(b.len(), 128);
    l2_distance_avx512(a, b)
}

#[inline(always)]
fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f64 {
    #[cfg(target_arch = "x86_64")]
    {
        if is_x86_feature_detected!("avx512f") {
            return unsafe { l2_distance_avx512_impl(a, b) };
        }
        if is_x86_feature_detected!("avx2") {
            return unsafe { l2_distance_avx2_impl(a, b) };
        }
    }
    l2_distance_scalar(a, b)
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
#[inline]
unsafe fn l2_distance_avx512_impl(a: &[f32], b: &[f32]) -> f64 {
    use std::arch::x86_64::*;

    let a_ptr = a.as_ptr();
    let b_ptr = b.as_ptr();

    // 128 floats = 8 x 16-float AVX-512 registers
    let mut sum0 = _mm512_setzero_ps();
    let mut sum1 = _mm512_setzero_ps();
    let mut sum2 = _mm512_setzero_ps();
    let mut sum3 = _mm512_setzero_ps();

    // Process 64 floats per iteration, 2 iterations
    for i in (0..128).step_by(64) {
        let a0 = _mm512_loadu_ps(a_ptr.add(i));
        let b0 = _mm512_loadu_ps(b_ptr.add(i));
        let d0 = _mm512_sub_ps(a0, b0);
        sum0 = _mm512_fmadd_ps(d0, d0, sum0);

        let a1 = _mm512_loadu_ps(a_ptr.add(i + 16));
        let b1 = _mm512_loadu_ps(b_ptr.add(i + 16));
        let d1 = _mm512_sub_ps(a1, b1);
        sum1 = _mm512_fmadd_ps(d1, d1, sum1);

        let a2 = _mm512_loadu_ps(a_ptr.add(i + 32));
        let b2 = _mm512_loadu_ps(b_ptr.add(i + 32));
        let d2 = _mm512_sub_ps(a2, b2);
        sum2 = _mm512_fmadd_ps(d2, d2, sum2);

        let a3 = _mm512_loadu_ps(a_ptr.add(i + 48));
        let b3 = _mm512_loadu_ps(b_ptr.add(i + 48));
        let d3 = _mm512_sub_ps(a3, b3);
        sum3 = _mm512_fmadd_ps(d3, d3, sum3);
    }

    let sum = _mm512_add_ps(_mm512_add_ps(sum0, sum1), _mm512_add_ps(sum2, sum3));
    _mm512_reduce_add_ps(sum) as f64
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2", enable = "fma")]
#[inline]
unsafe fn l2_distance_avx2_impl(a: &[f32], b: &[f32]) -> f64 {
    use std::arch::x86_64::*;

    let a_ptr = a.as_ptr();
    let b_ptr = b.as_ptr();

    let mut sum0 = _mm256_setzero_ps();
    let mut sum1 = _mm256_setzero_ps();
    let mut sum2 = _mm256_setzero_ps();
    let mut sum3 = _mm256_setzero_ps();

    for i in (0..128).step_by(32) {
        let a0 = _mm256_loadu_ps(a_ptr.add(i));
        let b0 = _mm256_loadu_ps(b_ptr.add(i));
        let d0 = _mm256_sub_ps(a0, b0);
        sum0 = _mm256_fmadd_ps(d0, d0, sum0);

        let a1 = _mm256_loadu_ps(a_ptr.add(i + 8));
        let b1 = _mm256_loadu_ps(b_ptr.add(i + 8));
        let d1 = _mm256_sub_ps(a1, b1);
        sum1 = _mm256_fmadd_ps(d1, d1, sum1);

        let a2 = _mm256_loadu_ps(a_ptr.add(i + 16));
        let b2 = _mm256_loadu_ps(b_ptr.add(i + 16));
        let d2 = _mm256_sub_ps(a2, b2);
        sum2 = _mm256_fmadd_ps(d2, d2, sum2);

        let a3 = _mm256_loadu_ps(a_ptr.add(i + 24));
        let b3 = _mm256_loadu_ps(b_ptr.add(i + 24));
        let d3 = _mm256_sub_ps(a3, b3);
        sum3 = _mm256_fmadd_ps(d3, d3, sum3);
    }

    let sum = _mm256_add_ps(_mm256_add_ps(sum0, sum1), _mm256_add_ps(sum2, sum3));
    // Horizontal sum
    let hi = _mm256_extractf128_ps(sum, 1);
    let lo = _mm256_castps256_ps128(sum);
    let sum128 = _mm_add_ps(lo, hi);
    let shuf = _mm_movehdup_ps(sum128);
    let sums = _mm_add_ps(sum128, shuf);
    let shuf2 = _mm_movehl_ps(sums, sums);
    let result = _mm_add_ss(sums, shuf2);
    _mm_cvtss_f32(result) as f64
}

#[inline]
fn l2_distance_scalar(a: &[f32], b: &[f32]) -> f64 {
    let mut sum: f32 = 0.0;
    for i in 0..a.len() {
        let d = a[i] - b[i];
        sum += d * d;
    }
    sum as f64
}

/// Batch L2 distance: compute distances from query to multiple vectors stored contiguously.
/// vectors_flat is a flat array of [n_vectors * 128] floats.
/// Returns distances as f32 for speed.
#[inline]
pub fn l2_distance_batch(query: &[f32], vectors_flat: &[f32], n_vectors: usize, distances: &mut [f32]) {
    debug_assert_eq!(query.len(), 128);
    debug_assert!(vectors_flat.len() >= n_vectors * 128);
    debug_assert!(distances.len() >= n_vectors);

    #[cfg(target_arch = "x86_64")]
    {
        if is_x86_feature_detected!("avx512f") {
            unsafe { l2_distance_batch_avx512(query, vectors_flat, n_vectors, distances) };
            return;
        }
    }

    for i in 0..n_vectors {
        let offset = i * 128;
        let v = &vectors_flat[offset..offset + 128];
        distances[i] = l2_distance_scalar(query, v) as f32;
    }
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
unsafe fn l2_distance_batch_avx512(query: &[f32], vectors_flat: &[f32], n_vectors: usize, distances: &mut [f32]) {
    use std::arch::x86_64::*;

    let q_ptr = query.as_ptr();
    // Pre-load query into registers
    let q0 = _mm512_loadu_ps(q_ptr);
    let q1 = _mm512_loadu_ps(q_ptr.add(16));
    let q2 = _mm512_loadu_ps(q_ptr.add(32));
    let q3 = _mm512_loadu_ps(q_ptr.add(48));
    let q4 = _mm512_loadu_ps(q_ptr.add(64));
    let q5 = _mm512_loadu_ps(q_ptr.add(80));
    let q6 = _mm512_loadu_ps(q_ptr.add(96));
    let q7 = _mm512_loadu_ps(q_ptr.add(112));

    let v_ptr = vectors_flat.as_ptr();

    for i in 0..n_vectors {
        let base = v_ptr.add(i * 128);

        let d0 = _mm512_sub_ps(q0, _mm512_loadu_ps(base));
        let mut sum = _mm512_mul_ps(d0, d0);

        let d1 = _mm512_sub_ps(q1, _mm512_loadu_ps(base.add(16)));
        sum = _mm512_fmadd_ps(d1, d1, sum);

        let d2 = _mm512_sub_ps(q2, _mm512_loadu_ps(base.add(32)));
        sum = _mm512_fmadd_ps(d2, d2, sum);

        let d3 = _mm512_sub_ps(q3, _mm512_loadu_ps(base.add(48)));
        sum = _mm512_fmadd_ps(d3, d3, sum);

        let d4 = _mm512_sub_ps(q4, _mm512_loadu_ps(base.add(64)));
        sum = _mm512_fmadd_ps(d4, d4, sum);

        let d5 = _mm512_sub_ps(q5, _mm512_loadu_ps(base.add(80)));
        sum = _mm512_fmadd_ps(d5, d5, sum);

        let d6 = _mm512_sub_ps(q6, _mm512_loadu_ps(base.add(96)));
        sum = _mm512_fmadd_ps(d6, d6, sum);

        let d7 = _mm512_sub_ps(q7, _mm512_loadu_ps(base.add(112)));
        sum = _mm512_fmadd_ps(d7, d7, sum);

        distances[i] = _mm512_reduce_add_ps(sum);
    }
}

use crate::api::*;
use crate::distance::{l2_distance, l2_distance_batch};
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

const DIM: usize = 128;
const NUM_CLUSTERS: usize = 256;
const NPROBE: usize = 16; // Number of clusters to search
const SAMPLE_SIZE: usize = 50000; // Number of vectors to sample for k-means
const KMEANS_ITERS: usize = 12;

struct Cluster {
    vectors: Vec<f32>,  // flat storage: [n * DIM]
    ids: Vec<u64>,
}

impl Cluster {
    fn new() -> Self {
        Self {
            vectors: Vec::new(),
            ids: Vec::new(),
        }
    }

    fn len(&self) -> usize {
        self.ids.len()
    }

    fn push(&mut self, id: u64, vector: &[f32]) {
        self.ids.push(id);
        self.vectors.extend_from_slice(vector);
    }
}

pub struct VectorDB {
    // Pre-index storage: vectors arrive before build_index
    pending_vectors: RwLock<Vec<f32>>,  // flat [n * DIM]
    pending_ids: RwLock<Vec<u64>>,
    pending_count: AtomicUsize,

    // IVF index
    centroids: RwLock<Vec<f32>>,  // [NUM_CLUSTERS * DIM]
    clusters: RwLock<Vec<RwLock<Cluster>>>,
    indexed: AtomicBool,
    build_threshold: usize,
}

impl VectorDB {
    pub fn new() -> Self {
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        Self {
            pending_vectors: RwLock::new(Vec::new()),
            pending_ids: RwLock::new(Vec::new()),
            pending_count: AtomicUsize::new(0),
            centroids: RwLock::new(Vec::new()),
            clusters: RwLock::new(Vec::new()),
            indexed: AtomicBool::new(false),
            build_threshold: 100_000,
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if self.indexed.load(Ordering::Relaxed) {
            // Assign to nearest cluster
            let centroids = self.centroids.read();
            let nearest = self.find_nearest_centroid(&vector, &centroids);
            let clusters = self.clusters.read();
            let mut cluster = clusters[nearest].write();
            cluster.push(id, &vector);
        } else {
            let mut vecs = self.pending_vectors.write();
            let mut ids = self.pending_ids.write();
            vecs.extend_from_slice(&vector);
            ids.push(id);
            self.pending_count.fetch_add(1, Ordering::Relaxed);
        }
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();

        if self.indexed.load(Ordering::Relaxed) {
            // Assign each vector to nearest cluster
            let centroids = self.centroids.read();
            let clusters = self.clusters.read();

            // Batch assign: compute cluster assignments first
            let assignments: Vec<(usize, u64, &[f32])> = vectors.iter().map(|(id, vec)| {
                let nearest = self.find_nearest_centroid(vec, &centroids);
                (nearest, *id, vec.as_slice())
            }).collect();

            for (cluster_idx, id, vec) in assignments {
                let mut cluster = clusters[cluster_idx].write();
                cluster.push(id, vec);
            }
        } else {
            let mut vecs = self.pending_vectors.write();
            let mut ids = self.pending_ids.write();
            vecs.reserve(count * DIM);
            ids.reserve(count);
            for (id, vector) in &vectors {
                vecs.extend_from_slice(vector);
                ids.push(*id);
            }
            let new_count = self.pending_count.fetch_add(count, Ordering::Relaxed) + count;

            // Build index when we have enough vectors
            if new_count >= self.build_threshold {
                drop(vecs);
                drop(ids);
                self.build_index();
            }
        }

        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        // If not indexed yet, build index first (shouldn't happen with 1M vectors)
        if !self.indexed.load(Ordering::Acquire) {
            self.build_index();
        }

        let top_k = top_k as usize;
        let centroids = self.centroids.read();
        let clusters = self.clusters.read();

        // Find nearest NPROBE clusters
        let n_clusters = centroids.len() / DIM;
        let mut cluster_dists: Vec<(f32, usize)> = Vec::with_capacity(n_clusters);

        // Compute distance to all centroids
        let mut centroid_distances = vec![0.0f32; n_clusters];
        l2_distance_batch(vector, &centroids, n_clusters, &mut centroid_distances);

        for (i, &dist) in centroid_distances.iter().enumerate() {
            cluster_dists.push((dist, i));
        }

        // Partial sort to find top NPROBE nearest clusters
        let nprobe = NPROBE.min(n_clusters);
        cluster_dists.select_nth_unstable_by(nprobe - 1, |a, b| a.0.partial_cmp(&b.0).unwrap());
        let nearest_clusters = &cluster_dists[..nprobe];

        // Search within selected clusters
        // Use a max-heap (BinaryHeap) for top-k
        let mut top_results: Vec<(f32, u64)> = Vec::with_capacity(top_k + 1);

        for &(_, cluster_idx) in nearest_clusters {
            let cluster = clusters[cluster_idx].read();
            let n = cluster.len();
            if n == 0 {
                continue;
            }

            let mut distances = vec![0.0f32; n];
            l2_distance_batch(vector, &cluster.vectors, n, &mut distances);

            for j in 0..n {
                let dist = distances[j];
                let id = cluster.ids[j];

                if top_results.len() < top_k {
                    top_results.push((dist, id));
                    if top_results.len() == top_k {
                        // Sort descending so worst is at end... actually use a simpler approach
                        top_results.sort_unstable_by(|a, b| b.0.partial_cmp(&a.0).unwrap());
                    }
                } else if dist < top_results[0].0 {
                    top_results[0] = (dist, id);
                    // Re-sort to maintain max at position 0
                    top_results.sort_unstable_by(|a, b| b.0.partial_cmp(&a.0).unwrap());
                }
            }
        }

        // Sort by distance ascending
        top_results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());

        top_results
            .iter()
            .map(|&(dist, id)| SearchResult {
                id,
                distance: dist as f64,
            })
            .collect()
    }

    fn find_nearest_centroid(&self, vector: &[f32], centroids: &[f32]) -> usize {
        let n_clusters = centroids.len() / DIM;
        let mut centroid_distances = vec![0.0f32; n_clusters];
        l2_distance_batch(vector, centroids, n_clusters, &mut centroid_distances);

        let mut best_idx = 0;
        let mut best_dist = f32::MAX;
        for (i, &d) in centroid_distances.iter().enumerate() {
            if d < best_dist {
                best_dist = d;
                best_idx = i;
            }
        }
        best_idx
    }

    fn build_index(&self) {
        if self.indexed.swap(true, Ordering::AcqRel) {
            return; // Already built
        }

        let vecs = self.pending_vectors.read();
        let ids = self.pending_ids.read();
        let n = ids.len();

        if n == 0 {
            return;
        }

        let n_clusters = NUM_CLUSTERS.min(n);

        // K-means clustering
        let centroids = self.run_kmeans(&vecs, n, n_clusters);

        // Assign all vectors to clusters
        let mut cluster_data: Vec<Cluster> = (0..n_clusters).map(|_| Cluster::new()).collect();

        // Batch assign using parallel processing
        let chunk_size = 10000;
        let n_chunks = (n + chunk_size - 1) / chunk_size;

        // Process chunks and collect assignments
        let assignments: Vec<Vec<(usize, usize)>> = (0..n_chunks)
            .into_par_iter()
            .map(|chunk_idx| {
                let start = chunk_idx * chunk_size;
                let end = (start + chunk_size).min(n);
                let chunk_n = end - start;
                let mut centroid_dists = vec![0.0f32; n_clusters];
                let mut local_assignments = Vec::with_capacity(chunk_n);

                for i in start..end {
                    let vec_slice = &vecs[i * DIM..(i + 1) * DIM];
                    l2_distance_batch(vec_slice, &centroids, n_clusters, &mut centroid_dists);

                    let mut best_idx = 0;
                    let mut best_dist = f32::MAX;
                    for (ci, &d) in centroid_dists.iter().enumerate() {
                        if d < best_dist {
                            best_dist = d;
                            best_idx = ci;
                        }
                    }
                    local_assignments.push((i, best_idx));
                }
                local_assignments
            })
            .collect();

        // Pre-calculate cluster sizes for pre-allocation
        let mut cluster_sizes = vec![0usize; n_clusters];
        for chunk in &assignments {
            for &(_, cluster_idx) in chunk {
                cluster_sizes[cluster_idx] += 1;
            }
        }

        // Pre-allocate cluster storage
        for (ci, cluster) in cluster_data.iter_mut().enumerate() {
            cluster.vectors.reserve(cluster_sizes[ci] * DIM);
            cluster.ids.reserve(cluster_sizes[ci]);
        }

        for chunk in &assignments {
            for &(vec_idx, cluster_idx) in chunk {
                let vec_slice = &vecs[vec_idx * DIM..(vec_idx + 1) * DIM];
                cluster_data[cluster_idx].push(ids[vec_idx], vec_slice);
            }
        }

        // Store
        *self.centroids.write() = centroids;
        let cluster_locks: Vec<RwLock<Cluster>> = cluster_data.into_iter().map(RwLock::new).collect();
        *self.clusters.write() = cluster_locks;

        eprintln!("Index built: {} vectors in {} clusters", n, n_clusters);
    }

    fn run_kmeans(&self, vecs: &[f32], n: usize, k: usize) -> Vec<f32> {
        // Sample vectors for k-means
        let sample_n = SAMPLE_SIZE.min(n);

        // Deterministic sampling: take evenly spaced vectors
        let step = n as f64 / sample_n as f64;
        let sample_indices: Vec<usize> = (0..sample_n)
            .map(|i| ((i as f64 * step) as usize).min(n - 1))
            .collect();

        // Initialize centroids: pick first k samples
        let mut centroids = vec![0.0f32; k * DIM];
        let init_step = sample_n as f64 / k as f64;
        for i in 0..k {
            let src_idx = sample_indices[((i as f64 * init_step) as usize).min(sample_n - 1)];
            centroids[i * DIM..(i + 1) * DIM].copy_from_slice(&vecs[src_idx * DIM..(src_idx + 1) * DIM]);
        }

        let mut assignments = vec![0usize; sample_n];
        let mut centroid_dists = vec![0.0f32; k];

        for _iter in 0..KMEANS_ITERS {
            // Assign each sample to nearest centroid
            for (si, &sample_idx) in sample_indices.iter().enumerate() {
                let vec_slice = &vecs[sample_idx * DIM..(sample_idx + 1) * DIM];
                l2_distance_batch(vec_slice, &centroids, k, &mut centroid_dists);

                let mut best_idx = 0;
                let mut best_dist = f32::MAX;
                for (ci, &d) in centroid_dists.iter().enumerate() {
                    if d < best_dist {
                        best_dist = d;
                        best_idx = ci;
                    }
                }
                assignments[si] = best_idx;
            }

            // Recompute centroids
            let mut new_centroids = vec![0.0f64; k * DIM];
            let mut counts = vec![0usize; k];

            for (si, &sample_idx) in sample_indices.iter().enumerate() {
                let ci = assignments[si];
                counts[ci] += 1;
                let src = &vecs[sample_idx * DIM..(sample_idx + 1) * DIM];
                let dst = &mut new_centroids[ci * DIM..(ci + 1) * DIM];
                for d in 0..DIM {
                    dst[d] += src[d] as f64;
                }
            }

            for ci in 0..k {
                if counts[ci] > 0 {
                    let c = counts[ci] as f64;
                    for d in 0..DIM {
                        centroids[ci * DIM + d] = (new_centroids[ci * DIM + d] / c) as f32;
                    }
                }
            }
        }

        centroids
    }
}

use crate::api::*;
use crate::distance::{l2_distance_batch};
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

const DIM: usize = 128;
const NUM_CLUSTERS: usize = 1024;
const NPROBE: usize = 32;
const SAMPLE_SIZE: usize = 60000;
const KMEANS_ITERS: usize = 10;

struct Cluster {
    vectors: Vec<f32>,  // flat storage: [n * DIM]
    ids: Vec<u64>,
}

impl Cluster {
    fn new() -> Self {
        Self {
            vectors: Vec::new(),
            ids: Vec::new(),
        }
    }

    fn len(&self) -> usize {
        self.ids.len()
    }

    fn push(&mut self, id: u64, vector: &[f32]) {
        self.ids.push(id);
        self.vectors.extend_from_slice(vector);
    }
}

pub struct VectorDB {
    // Pre-index storage
    pending_vectors: RwLock<Vec<f32>>,
    pending_ids: RwLock<Vec<u64>>,
    pending_count: AtomicUsize,

    // IVF index
    centroids: RwLock<Vec<f32>>,  // [NUM_CLUSTERS * DIM]
    clusters: RwLock<Vec<Cluster>>,
    indexed: AtomicBool,
    build_threshold: usize,
}

impl VectorDB {
    pub fn new() -> Self {
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        Self {
            pending_vectors: RwLock::new(Vec::new()),
            pending_ids: RwLock::new(Vec::new()),
            pending_count: AtomicUsize::new(0),
            centroids: RwLock::new(Vec::new()),
            clusters: RwLock::new(Vec::new()),
            indexed: AtomicBool::new(false),
            build_threshold: 100_000,
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vecs = self.pending_vectors.write();
        let mut ids = self.pending_ids.write();
        vecs.extend_from_slice(&vector);
        ids.push(id);
        self.pending_count.fetch_add(1, Ordering::Relaxed);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();

        let mut vecs = self.pending_vectors.write();
        let mut ids = self.pending_ids.write();
        vecs.reserve(count * DIM);
        ids.reserve(count);
        for (id, vector) in &vectors {
            vecs.extend_from_slice(vector);
            ids.push(*id);
        }
        self.pending_count.fetch_add(count, Ordering::Relaxed);

        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        // Build index on first search if not yet built
        if !self.indexed.load(Ordering::Acquire) {
            self.build_index();
        }

        let top_k = top_k as usize;
        let centroids = self.centroids.read();
        let clusters = self.clusters.read();

        let n_clusters = centroids.len() / DIM;
        let nprobe = NPROBE.min(n_clusters);

        // Compute distance to all centroids
        let mut centroid_distances = vec![0.0f32; n_clusters];
        l2_distance_batch(vector, &centroids, n_clusters, &mut centroid_distances);

        // Find top NPROBE nearest clusters using partial sort
        let mut cluster_indices: Vec<usize> = (0..n_clusters).collect();
        cluster_indices.select_nth_unstable_by(nprobe - 1, |&a, &b| {
            centroid_distances[a].partial_cmp(&centroid_distances[b]).unwrap()
        });

        // Collect top-k results using a max-heap approach
        // We maintain a sorted array (descending) of top_k best results
        // Position 0 = worst (largest distance)
        let mut heap: Vec<(f32, u64)> = Vec::with_capacity(top_k);
        let mut threshold = f32::MAX;

        for &cluster_idx in &cluster_indices[..nprobe] {
            let cluster = &clusters[cluster_idx];
            let n = cluster.len();
            if n == 0 {
                continue;
            }

            let mut distances = vec![0.0f32; n];
            l2_distance_batch(vector, &cluster.vectors, n, &mut distances);

            for j in 0..n {
                let dist = distances[j];

                if heap.len() < top_k {
                    heap.push((dist, cluster.ids[j]));
                    if heap.len() == top_k {
                        // Find the max to set threshold
                        heap.sort_unstable_by(|a, b| b.0.partial_cmp(&a.0).unwrap());
                        threshold = heap[0].0;
                    }
                } else if dist < threshold {
                    // Replace worst element
                    heap[0] = (dist, cluster.ids[j]);
                    // Re-find max (bubble down)
                    // Simple: re-sort since top_k is small (usually 10)
                    heap.sort_unstable_by(|a, b| b.0.partial_cmp(&a.0).unwrap());
                    threshold = heap[0].0;
                }
            }
        }

        // Sort by distance ascending
        heap.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());

        heap.iter()
            .map(|&(dist, id)| SearchResult {
                id,
                distance: dist as f64,
            })
            .collect()
    }

    fn build_index(&self) {
        if self.indexed.swap(true, Ordering::AcqRel) {
            return;
        }

        let vecs = self.pending_vectors.read();
        let ids = self.pending_ids.read();
        let n = ids.len();

        if n == 0 {
            return;
        }

        let n_clusters = NUM_CLUSTERS.min(n);
        eprintln!("Building index: {} vectors, {} clusters", n, n_clusters);

        // K-means clustering
        let centroids = self.run_kmeans(&vecs, n, n_clusters);

        // Assign all vectors to clusters - parallel
        let chunk_size = 10000;
        let n_chunks = (n + chunk_size - 1) / chunk_size;

        let assignments: Vec<Vec<(usize, usize)>> = (0..n_chunks)
            .into_par_iter()
            .map(|chunk_idx| {
                let start = chunk_idx * chunk_size;
                let end = (start + chunk_size).min(n);
                let mut centroid_dists = vec![0.0f32; n_clusters];
                let mut local_assignments = Vec::with_capacity(end - start);

                for i in start..end {
                    let vec_slice = &vecs[i * DIM..(i + 1) * DIM];
                    l2_distance_batch(vec_slice, &centroids, n_clusters, &mut centroid_dists);

                    let mut best_idx = 0;
                    let mut best_dist = f32::MAX;
                    for (ci, &d) in centroid_dists.iter().enumerate() {
                        if d < best_dist {
                            best_dist = d;
                            best_idx = ci;
                        }
                    }
                    local_assignments.push((i, best_idx));
                }
                local_assignments
            })
            .collect();

        // Build clusters
        let mut cluster_sizes = vec![0usize; n_clusters];
        for chunk in &assignments {
            for &(_, ci) in chunk {
                cluster_sizes[ci] += 1;
            }
        }

        let mut cluster_data: Vec<Cluster> = (0..n_clusters)
            .map(|ci| {
                let mut c = Cluster::new();
                c.vectors.reserve(cluster_sizes[ci] * DIM);
                c.ids.reserve(cluster_sizes[ci]);
                c
            })
            .collect();

        for chunk in &assignments {
            for &(vec_idx, ci) in chunk {
                let vec_slice = &vecs[vec_idx * DIM..(vec_idx + 1) * DIM];
                cluster_data[ci].push(ids[vec_idx], vec_slice);
            }
        }

        *self.centroids.write() = centroids;
        *self.clusters.write() = cluster_data;

        eprintln!("Index built successfully");
    }

    fn run_kmeans(&self, vecs: &[f32], n: usize, k: usize) -> Vec<f32> {
        let sample_n = SAMPLE_SIZE.min(n);
        let step = n as f64 / sample_n as f64;
        let sample_indices: Vec<usize> = (0..sample_n)
            .map(|i| ((i as f64 * step) as usize).min(n - 1))
            .collect();

        // Initialize centroids
        let mut centroids = vec![0.0f32; k * DIM];
        let init_step = sample_n as f64 / k as f64;
        for i in 0..k {
            let src_idx = sample_indices[((i as f64 * init_step) as usize).min(sample_n - 1)];
            centroids[i * DIM..(i + 1) * DIM].copy_from_slice(&vecs[src_idx * DIM..(src_idx + 1) * DIM]);
        }

        let mut assignments = vec![0usize; sample_n];
        let mut centroid_dists = vec![0.0f32; k];

        for _iter in 0..KMEANS_ITERS {
            // Assign
            for (si, &sample_idx) in sample_indices.iter().enumerate() {
                let vec_slice = &vecs[sample_idx * DIM..(sample_idx + 1) * DIM];
                l2_distance_batch(vec_slice, &centroids, k, &mut centroid_dists);

                let mut best_idx = 0;
                let mut best_dist = f32::MAX;
                for (ci, &d) in centroid_dists.iter().enumerate() {
                    if d < best_dist {
                        best_dist = d;
                        best_idx = ci;
                    }
                }
                assignments[si] = best_idx;
            }

            // Recompute centroids
            let mut new_centroids = vec![0.0f64; k * DIM];
            let mut counts = vec![0usize; k];

            for (si, &sample_idx) in sample_indices.iter().enumerate() {
                let ci = assignments[si];
                counts[ci] += 1;
                let src = &vecs[sample_idx * DIM..(sample_idx + 1) * DIM];
                let dst = &mut new_centroids[ci * DIM..(ci + 1) * DIM];
                for d in 0..DIM {
                    dst[d] += src[d] as f64;
                }
            }

            for ci in 0..k {
                if counts[ci] > 0 {
                    let c = counts[ci] as f64;
                    for d in 0..DIM {
                        centroids[ci * DIM + d] = (new_centroids[ci * DIM + d] / c) as f32;
                    }
                }
            }
        }

        centroids
    }
}

use crate::api::*;
use crate::distance::l2_distance_batch;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

const DIM: usize = 128;
const NUM_CLUSTERS: usize = 1024;
const NPROBE: usize = 24;
const SAMPLE_SIZE: usize = 60000;
const KMEANS_ITERS: usize = 12;

pub struct VectorDB {
    // Pre-index storage
    pending_vectors: RwLock<Vec<f32>>,
    pending_ids: RwLock<Vec<u64>>,
    pending_count: AtomicUsize,

    // IVF index - immutable after build
    centroids: RwLock<Option<Vec<f32>>>,       // [n_clusters * DIM]
    cluster_vectors: RwLock<Option<Vec<f32>>>,  // All vectors, grouped by cluster
    cluster_ids: RwLock<Option<Vec<u64>>>,      // All IDs, grouped by cluster
    cluster_offsets: RwLock<Option<Vec<usize>>>, // Start offset for each cluster (len = n_clusters+1)
    n_clusters: AtomicUsize,
    indexed: AtomicBool,
}

impl VectorDB {
    pub fn new() -> Self {
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        Self {
            pending_vectors: RwLock::new(Vec::with_capacity(1_100_000 * DIM)),
            pending_ids: RwLock::new(Vec::with_capacity(1_100_000)),
            pending_count: AtomicUsize::new(0),
            centroids: RwLock::new(None),
            cluster_vectors: RwLock::new(None),
            cluster_ids: RwLock::new(None),
            cluster_offsets: RwLock::new(None),
            n_clusters: AtomicUsize::new(0),
            indexed: AtomicBool::new(false),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vecs = self.pending_vectors.write();
        let mut ids = self.pending_ids.write();
        vecs.extend_from_slice(&vector);
        ids.push(id);
        self.pending_count.fetch_add(1, Ordering::Relaxed);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut vecs = self.pending_vectors.write();
        let mut ids = self.pending_ids.write();
        for (id, vector) in &vectors {
            vecs.extend_from_slice(vector);
            ids.push(*id);
        }
        self.pending_count.fetch_add(count, Ordering::Relaxed);
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        if !self.indexed.load(Ordering::Acquire) {
            self.build_index();
        }

        let top_k = top_k as usize;
        let centroids_guard = self.centroids.read();
        let centroids = centroids_guard.as_ref().unwrap();
        let cv_guard = self.cluster_vectors.read();
        let cluster_vecs = cv_guard.as_ref().unwrap();
        let ci_guard = self.cluster_ids.read();
        let cluster_ids = ci_guard.as_ref().unwrap();
        let co_guard = self.cluster_offsets.read();
        let offsets = co_guard.as_ref().unwrap();
        let n_clusters = self.n_clusters.load(Ordering::Relaxed);

        let nprobe = NPROBE.min(n_clusters);

        // Compute distance to all centroids
        let mut centroid_distances = vec![0.0f32; n_clusters];
        l2_distance_batch(vector, centroids, n_clusters, &mut centroid_distances);

        // Find top NPROBE nearest clusters
        let mut cluster_indices: Vec<u16> = (0..n_clusters as u16).collect();
        cluster_indices.select_nth_unstable_by(nprobe - 1, |&a, &b| {
            centroid_distances[a as usize]
                .partial_cmp(&centroid_distances[b as usize])
                .unwrap()
        });

        // Max-heap for top-k
        let mut heap: Vec<(f32, u64)> = Vec::with_capacity(top_k + 1);
        let mut threshold = f32::MAX;

        for &ci in &cluster_indices[..nprobe] {
            let ci = ci as usize;
            let start = offsets[ci];
            let end = offsets[ci + 1];
            let n = end - start;
            if n == 0 {
                continue;
            }

            let vec_start = start * DIM;
            let vec_end = end * DIM;
            let vecs_slice = &cluster_vecs[vec_start..vec_end];
            let ids_slice = &cluster_ids[start..end];

            let mut distances = vec![0.0f32; n];
            l2_distance_batch(vector, vecs_slice, n, &mut distances);

            for j in 0..n {
                let dist = distances[j];

                if heap.len() < top_k {
                    heap.push((dist, ids_slice[j]));
                    if heap.len() == top_k {
                        heap.sort_unstable_by(|a, b| b.0.partial_cmp(&a.0).unwrap());
                        threshold = heap[0].0;
                    }
                } else if dist < threshold {
                    heap[0] = (dist, ids_slice[j]);
                    // Sift down in max-heap style (for small top_k, sort is fine)
                    heap.sort_unstable_by(|a, b| b.0.partial_cmp(&a.0).unwrap());
                    threshold = heap[0].0;
                }
            }
        }

        heap.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());

        heap.iter()
            .map(|&(dist, id)| SearchResult {
                id,
                distance: dist as f64,
            })
            .collect()
    }

    fn build_index(&self) {
        if self.indexed.swap(true, Ordering::AcqRel) {
            return;
        }

        let vecs = self.pending_vectors.read();
        let ids = self.pending_ids.read();
        let n = ids.len();

        if n == 0 {
            return;
        }

        let n_clusters = NUM_CLUSTERS.min(n);
        self.n_clusters.store(n_clusters, Ordering::Relaxed);
        eprintln!("Building index: {} vectors, {} clusters", n, n_clusters);

        let centroids = self.run_kmeans(&vecs, n, n_clusters);

        // Parallel assignment
        let chunk_size = 10000;
        let n_chunks = (n + chunk_size - 1) / chunk_size;

        let all_assignments: Vec<usize> = {
            let chunks: Vec<Vec<usize>> = (0..n_chunks)
                .into_par_iter()
                .map(|chunk_idx| {
                    let start = chunk_idx * chunk_size;
                    let end = (start + chunk_size).min(n);
                    let mut centroid_dists = vec![0.0f32; n_clusters];
                    let mut local = Vec::with_capacity(end - start);

                    for i in start..end {
                        let vec_slice = &vecs[i * DIM..(i + 1) * DIM];
                        l2_distance_batch(vec_slice, &centroids, n_clusters, &mut centroid_dists);

                        let mut best_idx = 0;
                        let mut best_dist = f32::MAX;
                        for (ci, &d) in centroid_dists.iter().enumerate() {
                            if d < best_dist {
                                best_dist = d;
                                best_idx = ci;
                            }
                        }
                        local.push(best_idx);
                    }
                    local
                })
                .collect();

            let mut result = Vec::with_capacity(n);
            for chunk in chunks {
                result.extend(chunk);
            }
            result
        };

        // Count cluster sizes
        let mut cluster_sizes = vec![0usize; n_clusters];
        for &ci in &all_assignments {
            cluster_sizes[ci] += 1;
        }

        // Build offsets
        let mut offsets = vec![0usize; n_clusters + 1];
        for i in 0..n_clusters {
            offsets[i + 1] = offsets[i] + cluster_sizes[i];
        }

        // Place vectors into contiguous arrays ordered by cluster
        let mut cluster_vecs = vec![0.0f32; n * DIM];
        let mut cluster_ids_arr = vec![0u64; n];
        let mut write_pos = offsets[..n_clusters].to_vec(); // Current write position per cluster

        for i in 0..n {
            let ci = all_assignments[i];
            let pos = write_pos[ci];
            write_pos[ci] += 1;

            cluster_ids_arr[pos] = ids[i];
            let src = &vecs[i * DIM..(i + 1) * DIM];
            let dst_start = pos * DIM;
            cluster_vecs[dst_start..dst_start + DIM].copy_from_slice(src);
        }

        *self.centroids.write() = Some(centroids);
        *self.cluster_vectors.write() = Some(cluster_vecs);
        *self.cluster_ids.write() = Some(cluster_ids_arr);
        *self.cluster_offsets.write() = Some(offsets);

        eprintln!("Index built successfully");
    }

    fn run_kmeans(&self, vecs: &[f32], n: usize, k: usize) -> Vec<f32> {
        let sample_n = SAMPLE_SIZE.min(n);
        let step = n as f64 / sample_n as f64;
        let sample_indices: Vec<usize> = (0..sample_n)
            .map(|i| ((i as f64 * step) as usize).min(n - 1))
            .collect();

        let mut centroids = vec![0.0f32; k * DIM];
        let init_step = sample_n as f64 / k as f64;
        for i in 0..k {
            let src_idx = sample_indices[((i as f64 * init_step) as usize).min(sample_n - 1)];
            centroids[i * DIM..(i + 1) * DIM]
                .copy_from_slice(&vecs[src_idx * DIM..(src_idx + 1) * DIM]);
        }

        let mut assignments = vec![0usize; sample_n];

        for _iter in 0..KMEANS_ITERS {
            // Parallel assignment of samples to centroids
            let new_assignments: Vec<usize> = sample_indices
                .par_chunks(5000)
                .flat_map(|chunk| {
                    let mut centroid_dists = vec![0.0f32; k];
                    chunk.iter().map(|&sample_idx| {
                        let vec_slice = &vecs[sample_idx * DIM..(sample_idx + 1) * DIM];
                        l2_distance_batch(vec_slice, &centroids, k, &mut centroid_dists);

                        let mut best_idx = 0;
                        let mut best_dist = f32::MAX;
                        for (ci, &d) in centroid_dists.iter().enumerate() {
                            if d < best_dist {
                                best_dist = d;
                                best_idx = ci;
                            }
                        }
                        best_idx
                    }).collect::<Vec<_>>()
                })
                .collect();
            assignments = new_assignments;

            // Recompute centroids
            let mut new_centroids = vec![0.0f64; k * DIM];
            let mut counts = vec![0usize; k];

            for (si, &sample_idx) in sample_indices.iter().enumerate() {
                let ci = assignments[si];
                counts[ci] += 1;
                let src = &vecs[sample_idx * DIM..(sample_idx + 1) * DIM];
                let dst = &mut new_centroids[ci * DIM..(ci + 1) * DIM];
                for d in 0..DIM {
                    dst[d] += src[d] as f64;
                }
            }

            for ci in 0..k {
                if counts[ci] > 0 {
                    let c = counts[ci] as f64;
                    for d in 0..DIM {
                        centroids[ci * DIM + d] = (new_centroids[ci * DIM + d] / c) as f32;
                    }
                }
            }
        }

        centroids
    }
}

use crate::api::*;
use crate::distance::l2_distance_batch;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

const DIM: usize = 128;
const NUM_CLUSTERS: usize = 2048;
const NPROBE: usize = 40;
const SAMPLE_SIZE: usize = 80000;
const KMEANS_ITERS: usize = 12;

pub struct VectorDB {
    pending_vectors: RwLock<Vec<f32>>,
    pending_ids: RwLock<Vec<u64>>,
    pending_count: AtomicUsize,

    // IVF index - set once during build, then read-only
    index: RwLock<Option<IVFIndex>>,
    indexed: AtomicBool,
}

struct IVFIndex {
    centroids: Vec<f32>,        // [n_clusters * DIM]
    cluster_vectors: Vec<f32>,  // All vectors contiguous, grouped by cluster
    cluster_ids: Vec<u64>,      // All IDs, grouped by cluster
    cluster_offsets: Vec<usize>, // [n_clusters + 1] start/end offsets
    n_clusters: usize,
}

impl VectorDB {
    pub fn new() -> Self {
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        Self {
            pending_vectors: RwLock::new(Vec::with_capacity(1_100_000 * DIM)),
            pending_ids: RwLock::new(Vec::with_capacity(1_100_000)),
            pending_count: AtomicUsize::new(0),
            index: RwLock::new(None),
            indexed: AtomicBool::new(false),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vecs = self.pending_vectors.write();
        let mut ids = self.pending_ids.write();
        vecs.extend_from_slice(&vector);
        ids.push(id);
        self.pending_count.fetch_add(1, Ordering::Relaxed);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut vecs = self.pending_vectors.write();
        let mut ids = self.pending_ids.write();
        for (id, vector) in &vectors {
            vecs.extend_from_slice(vector);
            ids.push(*id);
        }
        self.pending_count.fetch_add(count, Ordering::Relaxed);
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        if !self.indexed.load(Ordering::Acquire) {
            self.build_index();
        }

        let top_k = top_k as usize;
        let index_guard = self.index.read();
        let idx = index_guard.as_ref().unwrap();

        let nprobe = NPROBE.min(idx.n_clusters);

        // Compute distance to all centroids
        let mut centroid_distances = vec![0.0f32; idx.n_clusters];
        l2_distance_batch(vector, &idx.centroids, idx.n_clusters, &mut centroid_distances);

        // Find top NPROBE nearest clusters
        let mut cluster_indices: Vec<u16> = (0..idx.n_clusters as u16).collect();
        cluster_indices.select_nth_unstable_by(nprobe - 1, |&a, &b| {
            centroid_distances[a as usize]
                .partial_cmp(&centroid_distances[b as usize])
                .unwrap()
        });

        // Sort the top nprobe by distance (search closest clusters first for better pruning)
        let top_clusters = &mut cluster_indices[..nprobe];
        top_clusters.sort_unstable_by(|&a, &b| {
            centroid_distances[a as usize]
                .partial_cmp(&centroid_distances[b as usize])
                .unwrap()
        });

        // Max-heap for top-k
        let mut heap: Vec<(f32, u64)> = Vec::with_capacity(top_k + 1);
        let mut threshold = f32::MAX;

        for &ci in top_clusters.iter() {
            let ci = ci as usize;
            let start = idx.cluster_offsets[ci];
            let end = idx.cluster_offsets[ci + 1];
            let n = end - start;
            if n == 0 {
                continue;
            }

            let vecs_slice = &idx.cluster_vectors[start * DIM..end * DIM];
            let ids_slice = &idx.cluster_ids[start..end];

            let mut distances = vec![0.0f32; n];
            l2_distance_batch(vector, vecs_slice, n, &mut distances);

            for j in 0..n {
                let dist = distances[j];

                if heap.len() < top_k {
                    heap.push((dist, ids_slice[j]));
                    if heap.len() == top_k {
                        heap.sort_unstable_by(|a, b| b.0.partial_cmp(&a.0).unwrap());
                        threshold = heap[0].0;
                    }
                } else if dist < threshold {
                    heap[0] = (dist, ids_slice[j]);
                    heap.sort_unstable_by(|a, b| b.0.partial_cmp(&a.0).unwrap());
                    threshold = heap[0].0;
                }
            }
        }

        heap.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());

        heap.iter()
            .map(|&(dist, id)| SearchResult {
                id,
                distance: dist as f64,
            })
            .collect()
    }

    fn build_index(&self) {
        if self.indexed.swap(true, Ordering::AcqRel) {
            return;
        }

        let vecs = self.pending_vectors.read();
        let ids = self.pending_ids.read();
        let n = ids.len();

        if n == 0 {
            return;
        }

        let n_clusters = NUM_CLUSTERS.min(n);
        eprintln!("Building index: {} vectors, {} clusters", n, n_clusters);

        let centroids = self.run_kmeans(&vecs, n, n_clusters);

        // Parallel assignment
        let chunk_size = 10000;
        let n_chunks = (n + chunk_size - 1) / chunk_size;

        let all_assignments: Vec<usize> = {
            let chunks: Vec<Vec<usize>> = (0..n_chunks)
                .into_par_iter()
                .map(|chunk_idx| {
                    let start = chunk_idx * chunk_size;
                    let end = (start + chunk_size).min(n);
                    let mut centroid_dists = vec![0.0f32; n_clusters];
                    let mut local = Vec::with_capacity(end - start);

                    for i in start..end {
                        let vec_slice = &vecs[i * DIM..(i + 1) * DIM];
                        l2_distance_batch(vec_slice, &centroids, n_clusters, &mut centroid_dists);

                        let mut best_idx = 0;
                        let mut best_dist = f32::MAX;
                        for (ci, &d) in centroid_dists.iter().enumerate() {
                            if d < best_dist {
                                best_dist = d;
                                best_idx = ci;
                            }
                        }
                        local.push(best_idx);
                    }
                    local
                })
                .collect();

            let mut result = Vec::with_capacity(n);
            for chunk in chunks {
                result.extend(chunk);
            }
            result
        };

        // Build contiguous cluster arrays
        let mut cluster_sizes = vec![0usize; n_clusters];
        for &ci in &all_assignments {
            cluster_sizes[ci] += 1;
        }

        let mut offsets = vec![0usize; n_clusters + 1];
        for i in 0..n_clusters {
            offsets[i + 1] = offsets[i] + cluster_sizes[i];
        }

        let mut cluster_vecs = vec![0.0f32; n * DIM];
        let mut cluster_ids_arr = vec![0u64; n];
        let mut write_pos = offsets[..n_clusters].to_vec();

        for i in 0..n {
            let ci = all_assignments[i];
            let pos = write_pos[ci];
            write_pos[ci] += 1;
            cluster_ids_arr[pos] = ids[i];
            let dst_start = pos * DIM;
            cluster_vecs[dst_start..dst_start + DIM]
                .copy_from_slice(&vecs[i * DIM..(i + 1) * DIM]);
        }

        *self.index.write() = Some(IVFIndex {
            centroids,
            cluster_vectors: cluster_vecs,
            cluster_ids: cluster_ids_arr,
            cluster_offsets: offsets,
            n_clusters,
        });

        // Free pending data
        drop(vecs);
        drop(ids);
        *self.pending_vectors.write() = Vec::new();
        *self.pending_ids.write() = Vec::new();

        eprintln!("Index built successfully");
    }

    fn run_kmeans(&self, vecs: &[f32], n: usize, k: usize) -> Vec<f32> {
        let sample_n = SAMPLE_SIZE.min(n);
        let step = n as f64 / sample_n as f64;
        let sample_indices: Vec<usize> = (0..sample_n)
            .map(|i| ((i as f64 * step) as usize).min(n - 1))
            .collect();

        let mut centroids = vec![0.0f32; k * DIM];
        let init_step = sample_n as f64 / k as f64;
        for i in 0..k {
            let src_idx = sample_indices[((i as f64 * init_step) as usize).min(sample_n - 1)];
            centroids[i * DIM..(i + 1) * DIM]
                .copy_from_slice(&vecs[src_idx * DIM..(src_idx + 1) * DIM]);
        }

        for _iter in 0..KMEANS_ITERS {
            // Parallel assignment
            let assignments: Vec<usize> = sample_indices
                .par_chunks(5000)
                .flat_map(|chunk| {
                    let mut centroid_dists = vec![0.0f32; k];
                    chunk
                        .iter()
                        .map(|&sample_idx| {
                            let vec_slice = &vecs[sample_idx * DIM..(sample_idx + 1) * DIM];
                            l2_distance_batch(
                                vec_slice,
                                &centroids,
                                k,
                                &mut centroid_dists,
                            );

                            let mut best_idx = 0;
                            let mut best_dist = f32::MAX;
                            for (ci, &d) in centroid_dists.iter().enumerate() {
                                if d < best_dist {
                                    best_dist = d;
                                    best_idx = ci;
                                }
                            }
                            best_idx
                        })
                        .collect::<Vec<_>>()
                })
                .collect();

            // Recompute centroids
            let mut new_centroids = vec![0.0f64; k * DIM];
            let mut counts = vec![0usize; k];

            for (si, &sample_idx) in sample_indices.iter().enumerate() {
                let ci = assignments[si];
                counts[ci] += 1;
                let src = &vecs[sample_idx * DIM..(sample_idx + 1) * DIM];
                let dst = &mut new_centroids[ci * DIM..(ci + 1) * DIM];
                for d in 0..DIM {
                    dst[d] += src[d] as f64;
                }
            }

            for ci in 0..k {
                if counts[ci] > 0 {
                    let c = counts[ci] as f64;
                    for d in 0..DIM {
                        centroids[ci * DIM + d] = (new_centroids[ci * DIM + d] / c) as f32;
                    }
                }
            }
        }

        centroids
    }
}

use crate::api::*;
use crate::distance::l2_distance_batch;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

const DIM: usize = 128;
const NUM_CLUSTERS: usize = 4096;
