    indexed: AtomicBool,
}

struct IVFIndex {
    centroids: Vec<f32>,        // [n_clusters * DIM], 64-byte aligned
    cluster_vectors: Vec<f32>,  // All vectors contiguous, grouped by cluster
    cluster_ids: Vec<u64>,
    cluster_offsets: Vec<usize>, // [n_clusters + 1]
    n_clusters: usize,
}

// Thread-local scratch buffers
thread_local! {
    static SCRATCH: std::cell::RefCell<ScratchBuffers> = std::cell::RefCell::new(ScratchBuffers::new());
}

struct ScratchBuffers {
    centroid_dists: Vec<f32>,
    cluster_indices: Vec<u16>,
    distances: Vec<f32>,
}

impl ScratchBuffers {
    fn new() -> Self {
        Self {
            centroid_dists: vec![0.0f32; NUM_CLUSTERS],
            cluster_indices: (0..NUM_CLUSTERS as u16).collect(),
            distances: vec![0.0f32; 8192], // max cluster size
        }
    }
}

impl VectorDB {
    pub fn new() -> Self {
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        Self {
            pending_vectors: RwLock::new(Vec::with_capacity(1_100_000 * DIM)),
            pending_ids: RwLock::new(Vec::with_capacity(1_100_000)),
            pending_count: AtomicUsize::new(0),
            index: RwLock::new(None),
            indexed: AtomicBool::new(false),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vecs = self.pending_vectors.write();
        let mut ids = self.pending_ids.write();
        vecs.extend_from_slice(&vector);
        ids.push(id);
        self.pending_count.fetch_add(1, Ordering::Relaxed);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut vecs = self.pending_vectors.write();
        let mut ids = self.pending_ids.write();
        for (id, vector) in &vectors {
            vecs.extend_from_slice(vector);
            ids.push(*id);
        }
        self.pending_count.fetch_add(count, Ordering::Relaxed);
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        if !self.indexed.load(Ordering::Acquire) {
            self.build_index();
        }

        let top_k = top_k as usize;
        let index_guard = self.index.read();
        let idx = index_guard.as_ref().unwrap();

        SCRATCH.with(|scratch| {
            let mut s = scratch.borrow_mut();

            let nprobe = NPROBE.min(idx.n_clusters);

            // Ensure buffers are large enough
            if s.centroid_dists.len() < idx.n_clusters {
                s.centroid_dists.resize(idx.n_clusters, 0.0);
                s.cluster_indices = (0..idx.n_clusters as u16).collect();
            }

            // Compute distance to all centroids
            l2_distance_batch(vector, &idx.centroids, idx.n_clusters, &mut s.centroid_dists);

            // Reset cluster indices
            for i in 0..idx.n_clusters {
                s.cluster_indices[i] = i as u16;
            }

            // Partial sort to find nearest nprobe clusters
            s.cluster_indices[..idx.n_clusters].select_nth_unstable_by(nprobe - 1, |&a, &b| {
                s.centroid_dists[a as usize]
                    .partial_cmp(&s.centroid_dists[b as usize])
                    .unwrap()
            });

            // Sort the top nprobe for better pruning (closest first)
            s.cluster_indices[..nprobe].sort_unstable_by(|&a, &b| {
                s.centroid_dists[a as usize]
                    .partial_cmp(&s.centroid_dists[b as usize])
                    .unwrap()
            });

            // Max-heap for top-k (position 0 = max)
            let mut heap: Vec<(f32, u64)> = Vec::with_capacity(top_k + 1);
            let mut threshold = f32::MAX;

            for idx_i in 0..nprobe {
                let ci = s.cluster_indices[idx_i] as usize;
                let start = idx.cluster_offsets[ci];
                let end = idx.cluster_offsets[ci + 1];
                let n = end - start;
                if n == 0 {
                    continue;
                }

                // Ensure distances buffer is large enough
                if s.distances.len() < n {
                    s.distances.resize(n, 0.0);
                }

                let vecs_slice = &idx.cluster_vectors[start * DIM..end * DIM];
                let ids_slice = &idx.cluster_ids[start..end];

                l2_distance_batch(vector, vecs_slice, n, &mut s.distances);

                for j in 0..n {
                    let dist = s.distances[j];

                    if heap.len() < top_k {
                        heap.push((dist, ids_slice[j]));
                        if heap.len() == top_k {
                            // Build max-heap: find max and put at position 0
                            heap.sort_unstable_by(|a, b| b.0.partial_cmp(&a.0).unwrap());
                            threshold = heap[0].0;
                        }
                    } else if dist < threshold {
                        heap[0] = (dist, ids_slice[j]);
                        // Restore heap property: simple sort for small top_k
                        heap.sort_unstable_by(|a, b| b.0.partial_cmp(&a.0).unwrap());
                        threshold = heap[0].0;
                    }
                }
            }

            heap.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());

            heap.iter()
                .map(|&(dist, id)| SearchResult {
                    id,
                    distance: dist as f64,
                })
                .collect()
        })
    }

    fn build_index(&self) {
        if self.indexed.swap(true, Ordering::AcqRel) {
            return;
        }

        let vecs = self.pending_vectors.read();
        let ids = self.pending_ids.read();
        let n = ids.len();

